import type {
  DashboardData,
  LiveScoresResponse,
  HistoryData,
  MatchupData,
  ApiResponse,
  Game,
} from '@/types'

const API_BASE = '/api'

async function fetchJson<T>(url: string, options?: RequestInit): Promise<T> {
  const response = await fetch(url, options)
  if (!response.ok) {
    throw new Error(`API error: ${response.status} ${response.statusText}`)
  }
  return response.json()
}

export const api = {
  // GET endpoints
  getDashboardData: (): Promise<DashboardData> =>
    fetchJson(`${API_BASE}/dashboard_data`),

  getLiveScores: (): Promise<LiveScoresResponse> =>
    fetchJson(`${API_BASE}/live_scores`),

  getLiveLines: (league: string): Promise<Game[]> =>
    fetchJson(`${API_BASE}/live_lines/${league}`),

  getHistoryData: (): Promise<HistoryData> =>
    fetchJson(`${API_BASE}/history_data`),

  getMatchupData: (gameId: number): Promise<MatchupData> =>
    fetchJson(`${API_BASE}/matchup_data/${gameId}`),

  // POST endpoints
  fetchGames: (): Promise<ApiResponse<void>> =>
    fetchJson('/fetch_games', { method: 'POST' }),

  fetchOdds: (): Promise<ApiResponse<void>> =>
    fetchJson('/fetch_odds', { method: 'POST' }),

  postDiscord: (): Promise<ApiResponse<void>> =>
    fetchJson('/post_discord', { method: 'POST' }),

  postDiscordWindow: (window: 'EARLY' | 'MID' | 'LATE'): Promise<ApiResponse<void>> =>
    fetchJson(`/post_discord_window/${window}`, { method: 'POST' }),

  checkResults: (): Promise<ApiResponse<void>> =>
    fetchJson('/check_results', { method: 'POST' }),

  updateResult: (pickId: number, result: 'W' | 'L' | 'P'): Promise<ApiResponse<void>> =>
    fetchJson(`/update_result/${pickId}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ result }),
    }),
}

export default api
